{
  "sentences": [
    {
      "text": "今天天氣很熱，我心情不好。",
      "pinyin": "Jīntiān tiānqì hěn rè, wǒ xīnqíng bù hǎo.",
      "pinyin_numeric": "jin1tian1 tian1qi4 hen3 re4, wo3 xin1qing2 bu4 hao3.",
      "translation_en": "The weather is very hot today, and I'm in a bad mood.",
      "translation_ko": "오늘 날씨가 매우 더워서 기분이 안 좋아요."
    },
    {
      "text": "昨天下午下雨，所以我很放鬆。",
      "pinyin": "Zuótiān xiàwǔ xiàyǔ, suǒyǐ wǒ hěn fàngsōng.",
      "pinyin_numeric": "zuo2tian1 xia4wu3 xia4yu3, suo3yi3 wo3 hen3 fang4song1.",
      "translation_en": "It rained yesterday afternoon, so I felt very relaxed.",
      "translation_ko": "어제 오후에 비가 와서 매우 편안했어요."
    },
    {
      "text": "明天是晴天，我們可以一起去公園。",
      "pinyin": "Míngtiān shì qíngtiān, wǒmen kěyǐ yīqǐ qù gōngyuán.",
      "pinyin_numeric": "ming2tian1 shi4 qing2tian1, wo3men5 ke3yi3 yi1qi3 qu4 gong1yuan2.",
      "translation_en": "Tomorrow will be sunny; we can go to the park together.",
      "translation_ko": "내일은 맑은 날씨라서 우리 함께 공원에 갈 수 있어요."
    },
    {
      "text": "颱風來了，天氣很悶熱，我有點緊張。",
      "pinyin": "Táifēng lái le, tiānqì hěn mēnrè, wǒ yǒudiǎn jǐnzhāng.",
      "pinyin_numeric": "tai2feng1 lai2 le5, tian1qi4 hen3 men1re4, wo3 you3dian3 jin3zhang1.",
      "translation_en": "A typhoon is coming; the weather is very muggy, and I'm a bit nervous.",
      "translation_ko": "태풍이 와서 날씨가 매우 후덥지근하고 조금 긴장돼요."
    },
    {
      "text": "今天溫度三十度，很熱，我沒有精神。",
      "pinyin": "Jīntiān wēndù sānshí dù, hěn rè, wǒ méiyǒu jīngshén.",
      "pinyin_numeric": "jin1tian1 wen1du4 san1shi2 du4, hen3 re4, wo3 mei2you3 jing1shen2.",
      "translation_en": "Today's temperature is 30 degrees; it's very hot, and I have no energy.",
      "translation_ko": "오늘 기온이 30도라서 매우 덥고 기운이 없어요."
    },
    {
      "text": "昨天是陰天，天氣很涼快，我很開心。",
      "pinyin": "Zuótiān shì yīntiān, tiānqì hěn liángkuài, wǒ hěn kāixīn.",
      "pinyin_numeric": "zuo2tian1 shi4 yin1tian1, tian1qi4 hen3 liang2kuai4, wo3 hen3 kai1xin1.",
      "translation_en": "Yesterday was cloudy; the weather was very cool, and I was very happy.",
      "translation_ko": "어제는 흐린 날씨였는데 매우 시원해서 기분이 좋았어요."
    },
    {
      "text": "今天天氣很冷，我穿外套，心情很好。",
      "pinyin": "Jīntiān tiānqì hěn lěng, wǒ chuān wàitào, xīnqíng hěn hǎo.",
      "pinyin_numeric": "jin1tian1 tian1qi4 hen3 leng3, wo3 chuan1 wai4tao4, xin1qing2 hen3 hao3.",
      "translation_en": "The weather is very cold today; I'm wearing a jacket, and my mood is great.",
      "translation_ko": "오늘 날씨가 매우 추워서 외투를 입었는데 기분이 좋아요."
    },
    {
      "text": "下雨了，路很滑，要小心走路。",
      "pinyin": "Xiàyǔ le, lù hěn huá, yào xiǎoxīn zǒulù.",
      "pinyin_numeric": "xia4yu3 le5, lu4 hen3 hua2, yao4 xiao3xin1 zou3lu4.",
      "translation_en": "It's raining; the road is very slippery; you need to walk carefully.",
      "translation_ko": "비가 와서 길이 매우 미끄러우니 조심해서 걸어야 해요."
    },
    {
      "text": "今天天氣很舒服，我有精神，想散步。",
      "pinyin": "Jīntiān tiānqì hěn shūfu, wǒ yǒu jīngshén, xiǎng sànbù.",
      "pinyin_numeric": "jin1tian1 tian1qi4 hen3 shu1fu5, wo3 you3 jing1shen2, xiang3 san4bu4.",
      "translation_en": "The weather is very comfortable today; I feel energetic and want to take a walk.",
      "translation_ko": "오늘 날씨가 매우 쾌적해서 기운이 나고 산책하고 싶어요."
    },
    {
      "text": "颱風天風很大，我壓力很大，很擔心。",
      "pinyin": "Táifēng tiān fēng hěn dà, wǒ yālì hěn dà, hěn dānxīn.",
      "pinyin_numeric": "tai2feng1 tian1 feng1 hen3 da4, wo3 ya1li4 hen3 da4, hen3 dan1xin1.",
      "translation_en": "On a typhoon day, the wind is very strong; I feel very stressed and worried.",
      "translation_ko": "태풍이 오는 날 바람이 매우 세서 스트레스가 크고 걱정돼요."
    }
  ]
}
